import { browserSupportsWebAuthn } from '@simplewebauthn/browser';
import { defineComponent } from 'vue';
import NcEmptyContent from '@nextcloud/vue/components/NcEmptyContent';
import NcTextField from '@nextcloud/vue/components/NcTextField';
import InformationIcon from 'vue-material-design-icons/InformationOutline.vue';
import LockOpenIcon from 'vue-material-design-icons/LockOpen.vue';
import LoginButton from "./LoginButton.vue";
import logger from "../../logger.js";
import { finishAuthentication, NoValidCredentials, startAuthentication } from "../../services/WebAuthnAuthenticationService.ts";
export default defineComponent({
  name: 'PasswordLessLoginForm',
  components: {
    LoginButton,
    InformationIcon,
    LockOpenIcon,
    NcEmptyContent,
    NcTextField
  },
  props: {
    username: {
      type: String,
      default: ''
    },
    redirectUrl: {
      type: [Boolean, String],
      default: false
    },
    autoCompleteAllowed: {
      type: Boolean,
      default: true
    },
    isHttps: {
      type: Boolean,
      default: false
    },
    isLocalhost: {
      type: Boolean,
      default: false
    }
  },
  setup() {
    return {
      supportsWebauthn: browserSupportsWebAuthn()
    };
  },
  data() {
    return {
      user: this.username,
      loading: false,
      validCredentials: true
    };
  },
  methods: {
    async authenticate() {
      // check required fields
      if (!this.$refs.loginForm.checkValidity()) {
        return;
      }
      logger.debug('passwordless login initiated');
      try {
        const params = await startAuthentication(this.user);
        await this.completeAuthentication(params);
      } catch (error) {
        if (error instanceof NoValidCredentials) {
          this.validCredentials = false;
          return;
        }
        logger.debug(error);
      }
    },
    changeUsername(username) {
      this.user = username;
      this.$emit('update:username', this.user);
    },
    completeAuthentication(challenge) {
      const redirectUrl = this.redirectUrl;
      return finishAuthentication(challenge).then(({
        defaultRedirectUrl
      }) => {
        logger.debug('Logged in redirecting'); // Redirect url might be false so || should be used instead of ??.
        window.location.href = redirectUrl || defaultRedirectUrl;
      }).catch(error => {
        logger.debug('GOT AN ERROR WHILE SUBMITTING CHALLENGE!', {
          error
        }); // Example: timeout, interaction refused...
      });
    },
    submit() {
      // noop
    }
  }
});